  "chunks": [
    {
      "chunk_type": "isnad",
      "arabic_text": "بَعْضُ أَصْحَابِنَا عَنْ عَبْدِ الْعَظِيمِ بْنِ عَبْدِ اللَّهِ الْحَسَنِيِّ عَنْ مَالِكِ بْنِ عَامِرٍ عَنِ الْمُفَضَّلِ بْنِ زَائِدَةَ عَنِ الْمُفَضَّلِ بْنِ عُمَرَ قَالَ",
      "translations": {
        "en": "Some of our companions, from ʿAbd al-ʿAẓīm ibn ʿAbdillāh al-Ḥasanī, from Mālik ibn ʿĀmir, from al-Mufaḍḍal ibn Zāʾidah, from al-Mufaḍḍal ibn ʿUmar, who said:"
      }
    },
    {
      "chunk_type": "opening",
      "arabic_text": "قَالَ أَبُو عَبْدِ اللَّهِ عَلَيْهِ السَّلَامُ:",
      "translations": {
        "en": "Abū ʿAbdillāh عليه السلام said:"
      }
    },
    {
      "chunk_type": "body",
      "arabic_text": "مَنْ دَانَ اللَّهَ بِغَيْرِ سَمَاعٍ عَنْ صَادِقٍ أَلْزَمَهُ اللَّهُ الْبَتَّةَ إِلَى الْعَنَاءِ، وَمَنِ ادَّعَى سَمَاعًا مِنْ غَيْرِ الْبَابِ الَّذِي فَتَحَهُ اللَّهُ فَهُوَ مُشْرِكٌ، وَذَلِكَ الْبَابُ الْمَأْمُونُ عَلَى سِرِّ اللَّهِ الْمَكْنُونِ."
      "translations": {
        "en": "Whoever practices religion toward Allah without hearing from a truthful one, Allah will inevitably bind him to hardship; and whoever claims hearing from other than the door which Allah has opened, then he is a mushrik; and that is the trusted door over the concealed secret of Allah."
      }
    }
  ],
  "translations": {
    "en": {
      "summary": "This hadith teaches that true religion must be taken through the divinely appointed truthful authority, not through unauthorized claims or independent invention. It stresses that access to Allah’s hidden guidance is through the secure door that Allah has opened, a central affirmation of Imam-based religious authority in Shia thought.",
      "seo_question": "Why does this hadith say religion must be taken only from the divinely opened door?",
      "key_terms": {
        "سَمَاعٍ": "receiving religious teaching by hearing from an authorized source",
        "صَادِقٍ": "a truthful authority, understood here as the divinely truthful Imam",
        "الْبَابِ": "the divinely appointed gate of access to true guidance",
        "مُشْرِكٌ": "one who associates partners with Allah by taking religion from an unauthorized source",
        "سِرِّ اللَّهِ الْمَكْنُونِ": "Allah’s concealed secret, meaning hidden divine knowledge entrusted to the proper authority",
        "الْمَأْمُونُ": "the one entrusted and secure in safeguarding divine knowledge",
        "الْعَنَاءِ": "hardship, strain, and misguiding burden resulting from false religious taking"
      }
    }
  },
